// ==================== REQUESTS MODULE ====================

// Load clients for request form
async function loadClientsForRequest() {
    let select = document.getElementById('request-client');
    if (!select) return;

    select.innerHTML = '<option value="" disabled selected>Select Client</option>';

    try {
        const clients = await API.getClients();
        
        if (!clients || clients.length === 0) {
            let option = document.createElement('option');
            option.value = '';
            option.disabled = true;
            option.textContent = 'No clients available. Please add clients first.';
            select.appendChild(option);
            return;
        }
        
        clients.forEach(client => {
            let option = document.createElement('option');
            option.value = client.id;
            option.textContent = client.name;
            select.appendChild(option);
        });
    } catch (error) {
        console.error('Error loading clients:', error);
    }
}

// Load cars for request form
async function loadCarsForRequest() {
    let select = document.getElementById('request-car');
    if (!select) return;

    select.innerHTML = '<option value="" disabled selected>Select Car</option>';

    try {
        const cars = await API.getCars();
        
        if (!cars || cars.length === 0) {
            let option = document.createElement('option');
            option.value = '';
            option.disabled = true;
            option.textContent = 'No cars available. Please add cars first.';
            select.appendChild(option);
            return;
        }
        
        cars.forEach(car => {
            let option = document.createElement('option');
            option.value = car.id;
            option.textContent = `${car.brand || ''} ${car.model || ''} (${car.year || ''}) - ${car.price || '0'} EGP`;
            select.appendChild(option);
        });
    } catch (error) {
        console.error('Error loading cars:', error);
    }
}

// Load clients for edit form
async function loadClientsForEdit(selectedClientId) {
    let select = document.getElementById('edit-request-client');
    if (!select) return;

    select.innerHTML = '<option value="" disabled>Select Client</option>';

    try {
        const clients = await API.getClients();
        
        if (!clients || clients.length === 0) {
            let option = document.createElement('option');
            option.value = '';
            option.disabled = true;
            option.textContent = 'No clients available. Please add clients first.';
            select.appendChild(option);
            return;
        }
        
        clients.forEach(client => {
            let option = document.createElement('option');
            option.value = client.id;
            option.textContent = client.name;
            if (client.id === selectedClientId) {
                option.selected = true;
            }
            select.appendChild(option);
        });
    } catch (error) {
        console.error('Error loading clients for edit:', error);
    }
}

// Load cars for edit form
async function loadCarsForEdit(selectedCarId) {
    let select = document.getElementById('edit-request-car');
    if (!select) return;

    select.innerHTML = '<option value="" disabled>Select Car</option>';

    try {
        const cars = await API.getCars();
        
        if (!cars || cars.length === 0) {
            let option = document.createElement('option');
            option.value = '';
            option.disabled = true;
            option.textContent = 'No cars available. Please add cars first.';
            select.appendChild(option);
            return;
        }
        
        cars.forEach(car => {
            let option = document.createElement('option');
            option.value = car.id;
            option.textContent = `${car.brand || ''} ${car.model || ''} (${car.year || ''}) - ${car.price || '0'} EGP`;
            if (car.id === selectedCarId) {
                option.selected = true;
            }
            select.appendChild(option);
        });
        
        if (selectedCarId && !cars.some(car => car.id === selectedCarId)) {
            let deletedCarOption = document.createElement('option');
            deletedCarOption.value = selectedCarId;
            deletedCarOption.disabled = true;
            deletedCarOption.textContent = '⚠️ The car no longer exists (it has been deleted)';
            deletedCarOption.style.backgroundColor = '#fff3f3';
            deletedCarOption.style.color = '#d32f2f';
            select.appendChild(deletedCarOption);
            deletedCarOption.selected = true;
        }
    } catch (error) {
        console.error('Error loading cars for edit:', error);
    }
}

// Load all requests
async function loadRequests() {
    showLoading(true);
    
    try {
        const [requests, clients, cars] = await Promise.all([
            API.getRequests(),
            API.getClients(),
            API.getCars()
        ]);
        
        renderRequests(requests, clients, cars);
    } catch (error) {
        console.error('Error loading requests:', error);
        showToast('Failed to load requests', 'error');
    } finally {
        showLoading(false);
    }
}

// Check if car exists
function isCarExists(carId, cars) {
    return cars && cars.some(car => car.id === carId);
}

// Render requests
function renderRequests(requests, clients, cars) {
    let list = document.querySelector('[data-screen="requests-list"] .content');
    if (!list) return;

    list.innerHTML = '';

    if (!requests || !requests.length) {
        list.innerHTML = `
            <div class="empty-state">
                <i class="fa-solid fa-file-lines"></i>
                <h3>No Requests Yet</h3>
                <p>Create your first request to get started</p>
            </div>
        `;
        return;
    }

    requests.forEach(req => {
        let client = clients.find(c => c.id === req.clientId);
        let car = cars.find(c => c.id === req.carId);
        let carExists = isCarExists(req.carId, cars);
        
        let statusClass = req.status === 'active' ? 'status-active' : 
                         req.status === 'completed' ? 'status-completed' : 'status-pending';

        let card = document.createElement('div');
        card.className = 'request-card';
        
        if (!carExists) {
            card.classList.add('warning');
        }

        let carDisplay = '';
        if (carExists && car) {
            carDisplay = `${car.brand || ''} ${car.model || ''} (${car.year || ''})`;
        } else if (req.carDetails) {
            carDisplay = `${req.carDetails.brand || ''} ${req.carDetails.model || ''} (${req.carDetails.year || ''})`;
        } else {
            carDisplay = '⚠️ Car no longer available';
        }

        let priceDisplay = '';
        if (carExists && car) {
            priceDisplay = (car.price || '0') + ' EGP';
        } else if (req.carDetails && req.carDetails.price) {
            priceDisplay = req.carDetails.price + ' EGP (old)';
        } else {
            priceDisplay = 'unavailable';
        }

        card.innerHTML = `
            <div class="request-header">
                <h4>${escapeHtml(req.title)}</h4>
                <span class="status ${statusClass}">${escapeHtml(req.status)}</span>
            </div>
            
            <div class="request-details">
                <p><i class="fa-solid fa-user"></i> Client: ${client ? escapeHtml(client.name) : 'Unknown'}</p>
                <p><i class="fa-solid fa-car"></i> Car: ${escapeHtml(carDisplay)}</p>
                <p><i class="fa-solid fa-tag"></i> Price: ${escapeHtml(priceDisplay)}</p>
                ${!carExists ? '<p class="warning-text"><i class="fa-solid fa-exclamation-triangle"></i> This car has been removed from the system.</p>' : ''}
            </div>

            <div class="request-actions">
                <button type="button" class="btn-icon btn-view" data-view-request="${req.id}">
                    <i class="fa-solid fa-eye"></i>
                </button>
                <button type="button" class="btn-icon btn-edit" data-edit-request="${req.id}">
                    <i class="fa-solid fa-pen"></i>
                </button>
                <button type="button" class="btn-icon btn-delete" data-delete-request="${req.id}">
                    <i class="fa-solid fa-trash"></i>
                </button>
            </div>
        `;

        list.appendChild(card);
    });
    
    // Add animation
    setTimeout(() => {
        const cards = list.querySelectorAll('.request-card');
        cards.forEach((card, index) => {
            card.style.animationDelay = `${index * 50}ms`;
            card.classList.add('animate-in');
        });
    }, 100);
}

// Add request
async function addRequest(clientId, carId, status) {
    if (!clientId || !carId) {
        showToast('Please select client and car', 'error');
        return;
    }

    showLoading(true);
    
    try {
        const [requests, clients, cars] = await Promise.all([
            API.getRequests(),
            API.getClients(),
            API.getCars()
        ]);
        
        const client = clients.find(c => c.id === clientId);
        const car = cars.find(c => c.id === carId);
        
        if (!client) {
            showToast('Client not found', 'error');
            return;
        }
        
        if (!car) {
            showToast('Car not found', 'error');
            return;
        }
        
        const title = `${car.brand} ${car.model} - Request`;
        
        const newRequest = {
            title: title,
            clientId: clientId,
            carId: carId,
            carDetails: {
                brand: car.brand,
                model: car.model,
                year: car.year,
                price: car.price,
                paint: car.paint,
                condition: car.condition,
                category: car.category
            },
            clientName: client.name,
            status: status || "active",
            createdAt: new Date().toISOString()
        };
        
        await API.addRequest(newRequest);
        
        showToast('Request added successfully', 'success');
        
        document.getElementById('request-client').value = '';
        document.getElementById('request-car').value = '';
        document.getElementById('request-status').value = 'active';
        
        loadRequests();
        showScreen('requests-list');
    } catch (error) {
        console.error('Error adding request:', error);
        showToast('Failed to add request', 'error');
    } finally {
        showLoading(false);
    }
}

// Load request details
async function loadRequestDetails(id) {
    showLoading(true);
    
    try {
        const [request, clients, cars] = await Promise.all([
            API.getRequest(id),
            API.getClients(),
            API.getCars()
        ]);
        
        if (!request) {
            showToast('Request not found', 'error');
            return;
        }
        
        let client = clients.find(c => c.id === request.clientId);
        let car = cars.find(c => c.id === request.carId);
        let carExists = isCarExists(request.carId, cars);
        
        renderRequestDetails(request, client, car, carExists);
        showScreen('request-details');
    } catch (error) {
        console.error('Error loading request details:', error);
        showToast('Failed to load request details', 'error');
    } finally {
        showLoading(false);
    }
}

// Render request details
function renderRequestDetails(request, client, car, carExists) {
    let box = document.querySelector('[data-screen="request-details"] .content');
    if (!box) return;

    let statusClass = request.status === 'active' ? 'status-active' : 
                     request.status === 'completed' ? 'status-completed' : 'status-pending';

    const carData = carExists && car ? car : (request.carDetails || {});
    
    let carDisplay = '';
    if (carExists && car) {
        carDisplay = `${car.brand || ''} ${car.model || ''} (${car.year || ''})`;
    } else if (request.carDetails) {
        carDisplay = `${request.carDetails.brand || ''} ${request.carDetails.model || ''} (${request.carDetails.year || ''})`;
    } else {
        carDisplay = 'not available';
    }

    let warningMessage = '';
    if (!carExists) {
        warningMessage = `
            <div class="warning-message">
                <i class="fa-solid fa-exclamation-triangle"></i> 
                <strong>Warning:</strong> This vehicle has been removed from the system. The data shown is from when the request was created.
            </div>`;
    }

    box.innerHTML = `
        <div class="card">
            <h3>${escapeHtml(request.title)}</h3>
            <hr>
            ${warningMessage}
            <p><strong><i class="fa-solid fa-user"></i> Client:</strong> ${client ? escapeHtml(client.name) : '-'}</p>
            <p><strong><i class="fa-solid fa-car"></i> Car:</strong> ${escapeHtml(carDisplay)}</p>
            <p><strong><i class="fa-solid fa-palette"></i> Paint:</strong> ${escapeHtml(carData.paint || 'N/A')}</p>
            <p><strong><i class="fa-solid fa-clipboard-list"></i> Condition:</strong> ${escapeHtml(carData.condition || 'N/A')}</p>
            <p><strong><i class="fa-solid fa-tag"></i> Category:</strong> ${escapeHtml(carData.category || 'N/A')}</p>
            <p><strong><i class="fa-solid fa-tag"></i> Price:</strong> ${escapeHtml(carData.price ? carData.price + ' EGP' : 'N/A')} ${!carExists && carData.price ? '(old)' : ''}</p>
            <p>
                <strong>Status:</strong>
                <span class="status ${statusClass}">
                    ${escapeHtml(request.status)}
                </span>
            </p>
            <p><strong>Created:</strong> ${new Date(request.createdAt).toLocaleDateString()}</p>
        </div>

        <div class="action-buttons">
            <button type="button" class="btn btn-secondary" data-go="requests-list">
                <i class="fa-solid fa-arrow-left"></i> Back
            </button>
            <button type="button" class="btn btn-warning" data-edit-request="${request.id}">
                <i class="fa-solid fa-pen"></i> Edit
            </button>
            <button type="button" class="btn btn-danger" data-delete-request="${request.id}">
                <i class="fa-solid fa-trash"></i> Delete
            </button>
        </div>
    `;
}

// Edit request
async function editRequest(id) {
    showLoading(true);
    
    try {
        const request = await API.getRequest(id);
        if (!request) {
            showToast('Request not found', 'error');
            return;
        }
        
        await loadClientsForEdit(request.clientId);
        await loadCarsForEdit(request.carId);
        
        let statusSelect = document.getElementById('edit-request-status');
        if (statusSelect) {
            statusSelect.value = request.status || 'active';
        }

        document.getElementById('update-request').dataset.id = id;

        showScreen('edit-request');
    } catch (error) {
        console.error('Error loading request for edit:', error);
        showToast('Failed to load request data', 'error');
    } finally {
        showLoading(false);
    }
}

// Update request
async function updateRequest(e) {
    e.preventDefault();
    
    let id = document.getElementById('update-request').dataset.id;
    let clientId = document.getElementById('edit-request-client').value;
    let carId = document.getElementById('edit-request-car').value;
    let status = document.getElementById('edit-request-status').value;

    if (!clientId || !carId) {
        showToast('Please select both client and car', 'error');
        return;
    }

    showLoading(true);
    
    try {
        const [requests, cars, clients] = await Promise.all([
            API.getRequests(),
            API.getCars(),
            API.getClients()
        ]);
        
        const requestIndex = requests.findIndex(r => r.id === id);
        const car = cars.find(c => c.id === carId);
        const client = clients.find(c => c.id === clientId);
        
        if (requestIndex !== -1) {
            if (!client) {
                showToast('Client not found', 'error');
                return;
            }
            
            let updatedRequest = {
                ...requests[requestIndex],
                clientId: clientId,
                carId: carId,
                clientName: client.name,
                status: status || "active",
                updatedAt: new Date().toISOString()
            };
            
            if (car) {
                updatedRequest.carDetails = {
                    brand: car.brand,
                    model: car.model,
                    year: car.year,
                    price: car.price,
                    paint: car.paint,
                    condition: car.condition,
                    category: car.category
                };
                updatedRequest.title = `${car.brand} ${car.model} - Request`;
            }
            
            await API.updateRequest(id, updatedRequest);
        }

        showToast('Request updated successfully', 'success');
        loadRequests();
        showScreen('requests-list');
    } catch (error) {
        console.error('Error updating request:', error);
        showToast('Failed to update request', 'error');
    } finally {
        showLoading(false);
    }
}

// Delete request
async function deleteRequest(id) {
    if (!confirm('Are you sure you want to delete this request?')) return;

    showLoading(true);
    
    try {
        await API.deleteRequest(id);
        showToast('Request deleted successfully', 'success');
        loadRequests();
        showScreen('requests-list');
    } catch (error) {
        console.error('Error deleting request:', error);
        showToast('Failed to delete request', 'error');
    } finally {
        showLoading(false);
    }
}

// Show loading state
function showLoading(show) {
    const container = document.querySelector('[data-screen="requests-list"] .content');
    if (!container) return;
    
    if (show) {
        const loadingDiv = document.createElement('div');
        loadingDiv.className = 'loading-overlay';
        loadingDiv.innerHTML = `
            <div class="loading-spinner">
                <div class="spinner"></div>
                <p>Loading requests...</p>
            </div>
        `;
        container.appendChild(loadingDiv);
    } else {
        const loadingOverlay = container.querySelector('.loading-overlay');
        if (loadingOverlay) loadingOverlay.remove();
    }
}

// Escape HTML
function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// Event listeners
document.addEventListener('DOMContentLoaded', function() {
    // View request buttons
    document.querySelectorAll('[data-view-request]').forEach(btn => {
        btn.addEventListener('click', function(e) {
            e.preventDefault();
            loadRequestDetails(this.dataset.viewRequest);
        });
    });

    // Delete request buttons
    document.querySelectorAll('[data-delete-request]').forEach(btn => {
        btn.addEventListener('click', function(e) {
            e.preventDefault();
            deleteRequest(this.dataset.deleteRequest);
        });
    });

    // Edit request buttons
    document.querySelectorAll('[data-edit-request]').forEach(btn => {
        btn.addEventListener('click', function(e) {
            e.preventDefault();
            editRequest(this.dataset.editRequest);
        });
    });

    // Save request button
    document.querySelectorAll('[data-save-request]').forEach(btn => {
        btn.addEventListener('click', function(e) {
            e.preventDefault();
            let clientEl = document.getElementById('request-client');
            let carEl = document.getElementById('request-car');
            let statusEl = document.getElementById('request-status');

            if (!clientEl || !carEl) {
                showToast('Form not ready', 'error');
                return;
            }

            let clientId = clientEl.value;
            let carId = carEl.value;
            let status = statusEl ? statusEl.value : 'active';

            if (!clientId || !carId) {
                showToast('Please select both client and car', 'error');
                return;
            }

            addRequest(clientId, carId, status);
        });
    });

    // Update request button
    const updateBtn = document.getElementById('update-request');
    if (updateBtn) {
        updateBtn.addEventListener('click', updateRequest);
    }
});

// Load data when entering add request screen
document.querySelectorAll('[data-go="add-request"]').forEach(btn => {
    btn.addEventListener('click', function() {
        setTimeout(() => {
            loadClientsForRequest();
            loadCarsForRequest();
        }, 100);
    });
});

// Make functions globally available
window.loadRequests = loadRequests;
window.loadRequestDetails = loadRequestDetails;
window.loadClientsForRequest = loadClientsForRequest;
window.loadCarsForRequest = loadCarsForRequest;